export const getListArticlesUrl = (
  projectId: number,
  params?: ListArticlesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/projects/${projectId}/articles?${stringifiedParams}`
    : `/api/projects/${projectId}/articles`;
};

export const listArticles = async (
  projectId: number,
  params?: ListArticlesParams,
  options?: RequestInit,
): Promise<Article[]> => {
  return customFetch<Article[]>(getListArticlesUrl(projectId, params), {
    ...options,
    method: "GET",
  });
};

export const getListArticlesQueryKey = (
  projectId: number,
  params?: ListArticlesParams,
) => {
  return [
    `/api/projects/${projectId}/articles`,
    ...(params ? [params] : []),
  ] as const;
};

